('sport-studies:3-3-1-during-the-event:fib:af206207', 'sport-studies', 'sport-studies:3-3-1-during-the-event', '3.3.1 During the Event', 'fib', 'fib', 1, '{"question": "Areas away from the host venues can feel _____ if attention and money focus elsewhere.", "blankOptions": {"B1": ["infrastructure", "short-term", "neglected", "pride"]}}'::jsonb, '{"blanks": {"B1": "neglected"}}'::jsonb),
('sport-studies:3-3-1-during-the-event:fib:0a689fe9', 'sport-studies', 'sport-studies:3-3-1-during-the-event', '3.3.1 During the Event', 'fib', 'fib', 1, '{"question": "If the host team performs badly, this can damage the national _____ that hosting was meant to build.", "blankOptions": {"B1": ["short-term", "pride", "direct", "cohesion"]}}'::jsonb, '{"blanks": {"B1": "pride"}}'::jsonb),
('sport-studies:3-3-1-during-the-event:match:f2e33122', 'sport-studies', 'sport-studies:3-3-1-during-the-event', '3.3.1 During the Event', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Social infrastructure in use”?", "options": ["A shared, feel-good sense of pride and unity across the country while the event is running", "Visitor spending tied straight to the event, such as tickets and hotel stays right next to a venue", "Extra visitor spending nearby that is not the event itself, such as meals and sightseeing", "Venues, transport and facilities built beforehand now genuinely being used by visitors and residents"]}'::jsonb, '{"answer": 3, "explain": "“Social infrastructure in use” means: Venues, transport and facilities built beforehand now genuinely being used by visitors and residents"}'::jsonb),
('sport-studies:3-3-1-during-the-event:match:8c414553', 'sport-studies', 'sport-studies:3-3-1-during-the-event', '3.3.1 During the Event', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “National morale / social cohesion”?", "options": ["Temporary jobs, such as stewarding and security, created only to cover the event period", "The chance of a security threat rising because a major event gathers huge crowds in one place", "Venues, transport and facilities built beforehand now genuinely being used by visitors and residents", "A shared, feel-good sense of pride and unity across the country while the event is running"]}'::jsonb, '{"answer": 3, "explain": "“National morale / social cohesion” means: A shared, feel-good sense of pride and unity across the country while the event is running"}'::jsonb),
('sport-studies:3-3-1-during-the-event:match:ab046e88', 'sport-studies', 'sport-studies:3-3-1-during-the-event', '3.3.1 During the Event', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “National status”?", "options": ["The chance of a security threat rising because a major event gathers huge crowds in one place", "Visitor spending tied straight to the event, such as tickets and hotel stays right next to a venue", "How the country is seen and respected by other nations while it is in the international spotlight", "Temporary jobs, such as stewarding and security, created only to cover the event period"]}'::jsonb, '{"answer": 2, "explain": "“National status” means: How the country is seen and respected by other nations while it is in the international spotlight"}'::jsonb),
('sport-studies:3-3-1-during-the-event:match:18e6b972', 'sport-studies', 'sport-studies:3-3-1-during-the-event', '3.3.1 During the Event', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Direct tourism”?", "options": ["Visitor spending tied straight to the event, such as tickets and hotel stays right next to a venue", "How the country is seen and respected by other nations while it is in the international spotlight", "Venues, transport and facilities built beforehand now genuinely being used by visitors and residents", "Extra visitor spending nearby that is not the event itself, such as meals and sightseeing"]}'::jsonb, '{"answer": 0, "explain": "“Direct tourism” means: Visitor spending tied straight to the event, such as tickets and hotel stays right next to a venue"}'::jsonb),
('sport-studies:3-3-1-during-the-event:match:9eb51085', 'sport-studies', 'sport-studies:3-3-1-during-the-event', '3.3.1 During the Event', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Indirect tourism”?", "options": ["How the country is seen and respected by other nations while it is in the international spotlight", "Extra visitor spending nearby that is not the event itself, such as meals and sightseeing", "A shared, feel-good sense of pride and unity across the country while the event is running", "Visitor spending tied straight to the event, such as tickets and hotel stays right next to a venue"]}'::jsonb, '{"answer": 1, "explain": "“Indirect tourism” means: Extra visitor spending nearby that is not the event itself, such as meals and sightseeing"}'::jsonb),
('sport-studies:3-3-1-during-the-event:match:dbf91f8d', 'sport-studies', 'sport-studies:3-3-1-during-the-event', '3.3.1 During the Event', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Short-term employment”?", "options": ["Temporary jobs, such as stewarding and security, created only to cover the event period", "Venues, transport and facilities built beforehand now genuinely being used by visitors and residents", "Visitor spending tied straight to the event, such as tickets and hotel stays right next to a venue", "How the country is seen and respected by other nations while it is in the international spotlight"]}'::jsonb, '{"answer": 0, "explain": "“Short-term employment” means: Temporary jobs, such as stewarding and security, created only to cover the event period"}'::jsonb),
('sport-studies:3-3-1-during-the-event:match:6512b27e', 'sport-studies', 'sport-studies:3-3-1-during-the-event', '3.3.1 During the Event', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Regional neglect”?", "options": ["Areas away from the host venues feeling left out while attention and money focus elsewhere", "Venues, transport and facilities built beforehand now genuinely being used by visitors and residents", "Temporary jobs, such as stewarding and security, created only to cover the event period", "A shared, feel-good sense of pride and unity across the country while the event is running"]}'::jsonb, '{"answer": 0, "explain": "“Regional neglect” means: Areas away from the host venues feeling left out while attention and money focus elsewhere"}'::jsonb),
('sport-studies:3-3-1-during-the-event:match:f7986dbc', 'sport-studies', 'sport-studies:3-3-1-during-the-event', '3.3.1 During the Event', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Terrorism and crime risk”?", "options": ["How the country is seen and respected by other nations while it is in the international spotlight", "The chance of a security threat rising because a major event gathers huge crowds in one place", "A shared, feel-good sense of pride and unity across the country while the event is running", "Extra visitor spending nearby that is not the event itself, such as meals and sightseeing"]}'::jsonb, '{"answer": 1, "explain": "“Terrorism and crime risk” means: The chance of a security threat rising because a major event gathers huge crowds in one place"}'::jsonb),
('sport-studies:3-3-2-post-event-and-legacy:exam:ffafc4ec', 'sport-studies', 'sport-studies:3-3-2-post-event-and-legacy', '3.3.2 Post-Event and Legacy', 'exam', 'mcq', 1, '{"num": "2", "question": "Which best describes a ''white elephant'' in the context of an event''s legacy?", "options": ["A purpose-built venue that is left unused once the event has finished", "A new rail line that continues to serve passengers for years afterwards", "A local sports club that gains hundreds of new members after the event", "A rise in ticket sales for the sport that featured at the event"], "hint": "Think about which option describes a venue with no ongoing use, rather than a positive outcome.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: A — A purpose-built venue that is left unused once the event has finished.</strong></p>\n<ul>\n<li>A ''white elephant'' is specifically a venue with no ongoing use or income after the closing ceremony.</li>\n<li>The other options all describe positive legacies (a lasting transport link, a participation rise, or a profile rise), not a white elephant.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('sport-studies:3-3-2-post-event-and-legacy:mcq:f0fdd424', 'sport-studies', 'sport-studies:3-3-2-post-event-and-legacy', '3.3.2 Post-Event and Legacy', 'mcq', 'mcq', 1, '{"question": "What does the word ''legacy'' mean in the context of hosting a major sporting event?", "options": ["The lasting effect that remains once the event itself has finished", "The total number of tickets sold across every day of the event", "The official title given to the host city during the opening ceremony", "The list of sports included in that particular event''s programme"]}'::jsonb, '{"answer": 0, "explain": "Legacy is what is left behind afterwards — facilities, participation, profile, reputation and investment — not ticket sales, a ceremonial title, or the sports list."}'::jsonb),
('sport-studies:3-3-2-post-event-and-legacy:mcq:2ff6de9b', 'sport-studies', 'sport-studies:3-3-2-post-event-and-legacy', '3.3.2 Post-Event and Legacy', 'mcq', 'mcq', 1, '{"question": "Which of these is an example of a positive transport and infrastructure legacy?", "options": ["A new rail line built for the event that continues to serve the city for years afterwards", "A temporary road closure put in place for the event that is lifted the moment the closing ceremony finally ends", "A short-term security operation that stops once the last spectator has left", "A rise in hotel prices during the fortnight the event is actually taking place"]}'::jsonb, '{"answer": 0, "explain": "A rail line that keeps serving the city afterwards is a lasting infrastructure legacy. Temporary closures, short-term security and event-week price rises all end when the event does."}'::jsonb),
('sport-studies:3-3-2-post-event-and-legacy:mcq:f28b019e', 'sport-studies', 'sport-studies:3-3-2-post-event-and-legacy', '3.3.2 Post-Event and Legacy', 'mcq', 'mcq', 1, '{"question": "A national governing body notices far more people signing up for its sport in the two years after a major event was held in the country. This shows...", "options": ["a legacy of increased participation and a raised profile for that sport", "that the international status and reputation of the host nation has clearly fallen since the event finished", "that the event''s main facilities have become white elephants", "that ticket revenue exceeded the total cost of hosting the event"]}'::jsonb, '{"answer": 0, "explain": "More people taking up the sport, and more attention on it, is exactly what a participation-and-profile legacy looks like — the other options describe unrelated or opposite outcomes."}'::jsonb),
('sport-studies:3-3-2-post-event-and-legacy:mcq:f73c086f', 'sport-studies', 'sport-studies:3-3-2-post-event-and-legacy', '3.3.2 Post-Event and Legacy', 'mcq', 'mcq', 1, '{"question": "A city spends far more hosting an event than it earns back from tickets, sponsorship and tourism. This is best described as...", "options": ["a legacy of improved social infrastructure for local residents", "the event cost more to stage than it earned back", "a rise in participation across the sports that were involved", "an increase in future financial investment in the city"]}'::jsonb, '{"answer": 1, "explain": "Spending more than the event earns back is the cost-versus-revenue negative — not an infrastructure legacy, a participation rise, or increased investment."}'::jsonb),
('sport-studies:3-3-2-post-event-and-legacy:mcq:53825d32', 'sport-studies', 'sport-studies:3-3-2-post-event-and-legacy', '3.3.2 Post-Event and Legacy', 'mcq', 'mcq', 1, '{"question": "Which best describes a raised international profile as a legacy of hosting a major event?", "options": ["The host is seen worldwide as capable of delivering a major event, attracting future investment", "The host nation''s own athletes are permanently guaranteed to win more medals at every single major event held after this one", "The host city automatically loses the right to bid for any future event", "Ticket prices for the event rise sharply during the closing ceremony itself"]}'::jsonb, '{"answer": 0, "explain": "A raised profile is about international reputation and future investment, not guaranteed medals, losing future bidding rights, or ceremony-week ticket prices."}'::jsonb),
('sport-studies:3-3-2-post-event-and-legacy:mcq:3b902de2', 'sport-studies', 'sport-studies:3-3-2-post-event-and-legacy', '3.3.2 Post-Event and Legacy', 'mcq', 'mcq', 1, '{"question": "A newly built arena stands empty for years after the closing ceremony, while the host nation is also criticised internationally for how badly the event was organised. This scenario shows...", "options": ["two positive legacies: new facilities in constant use, and a raised international profile", "a ''white elephant'' venue combined with a loss of national reputation", "an increase in participation together with a rise in the sport''s profile", "improved transport infrastructure alongside increased future investment"]}'::jsonb, '{"answer": 1, "explain": "An unused venue is a white elephant, and international criticism of the organisation is reputational loss — both negative legacies, not the positive pairs in the other options."}'::jsonb),
('sport-studies:3-3-2-post-event-and-legacy:tf:6c42ab64', 'sport-studies', 'sport-studies:3-3-2-post-event-and-legacy', '3.3.2 Post-Event and Legacy', 'tf', 'tf', 1, '{"question": "A ''legacy'' can only ever be a positive result of hosting a major event."}'::jsonb, '{"answer": false, "explain": "Legacy can be positive, negative, or both at once — a host can gain a busy new pool AND an empty arena from the same event."}'::jsonb),
('sport-studies:3-3-2-post-event-and-legacy:tf:0dfc16e3', 'sport-studies', 'sport-studies:3-3-2-post-event-and-legacy', '3.3.2 Post-Event and Legacy', 'tf', 'tf', 1, '{"question": "A rise in participation in the sports featured at an event is an example of a positive legacy."}'::jsonb, '{"answer": true, "explain": "More people taking up the sports involved, inspired by watching the event, is exactly what a positive participation legacy looks like."}'::jsonb),
('sport-studies:3-3-2-post-event-and-legacy:tf:1199e25f', 'sport-studies', 'sport-studies:3-3-2-post-event-and-legacy', '3.3.2 Post-Event and Legacy', 'tf', 'tf', 1, '{"question": "A ''white elephant'' is the nickname for a venue that stays in constant public use long after the event has finished."}'::jsonb, '{"answer": false, "explain": "It is the opposite — a ''white elephant'' is a venue left unused once the event is over, not one that is thriving afterwards."}'::jsonb),
('sport-studies:3-3-2-post-event-and-legacy:tf:e80d8e06', 'sport-studies', 'sport-studies:3-3-2-post-event-and-legacy', '3.3.2 Post-Event and Legacy', 'tf', 'tf', 1, '{"question": "Hosting a major event is always guaranteed to bring in more revenue than it costs to host."}'::jsonb, '{"answer": false, "explain": "There is no such guarantee — what an event earns back can end up lower than what it cost to stage, leaving a financial loss."}'::jsonb),
('sport-studies:3-3-2-post-event-and-legacy:tf:20c86e60', 'sport-studies', 'sport-studies:3-3-2-post-event-and-legacy', '3.3.2 Post-Event and Legacy', 'tf', 'tf', 1, '{"question": "A host nation''s international reputation can be damaged by poor organisation or a scandal, even after the event has ended."}'::jsonb, '{"answer": true, "explain": "Reputational loss is a genuine negative legacy — bad organisation, poor host performance, or a scandal can all damage standing that outlasts the event."}'::jsonb),
('sport-studies:3-3-2-post-event-and-legacy:tf:7d378c67', 'sport-studies', 'sport-studies:3-3-2-post-event-and-legacy', '3.3.2 Post-Event and Legacy', 'tf', 'tf', 1, '{"question": "Improved transport and social infrastructure built for an event can continue to benefit the local area long after the event finishes."}'::jsonb, '{"answer": true, "explain": "That is exactly what a positive transport and infrastructure legacy means — new roads, rail links or regeneration that outlast the event itself."}'::jsonb),
('sport-studies:3-3-2-post-event-and-legacy:learn:5bf15b44', 'sport-studies', 'sport-studies:3-3-2-post-event-and-legacy', '3.3.2 Post-Event and Legacy', 'learn', 'mcq', 1, '{"readingTitle": "What happens after the event — and what ''legacy'' means", "reading": "<h4>The three stages the spec splits an event into</h4>\n<ul>\n<li>The specification looks at hosting a major event in three separate stages: <strong>before</strong> the event (bidding and building), <strong>during</strong> the event itself, and <strong>after</strong> the event has finished.</li>\n<li>This page covers the <strong>after</strong> stage only — what a host city or nation is left with once the event is over. (Pre-event aspects and during-event aspects are covered on their own pages.)</li>\n</ul>\n<h4>What ''legacy'' means</h4>\n<ul>\n<li><strong>Legacy</strong> is the lasting effect an event leaves behind once the excitement of the event itself has faded — the facilities, habits, reputation and investment that remain months or years later.</li>\n<li>A legacy can show up <strong>immediately</strong> (within months) or only become clear <strong>long-term</strong> (years later), and it can be <strong>positive, negative, or both at the same time</strong>.</li>\n<li>The exam keeps testing whether you can treat legacy as a <strong>balance</strong> to weigh up — not just list one side of it.</li>\n</ul>", "question": "Which stage of hosting a major event does the word ''legacy'' describe?", "options": ["The stage where cities compete to be chosen as the host", "What is left behind once the event itself has finished", "The build-up in the weeks immediately before the opening ceremony", "The rules officials use to run the competition during the event"]}'::jsonb, '{"answer": 1, "explain": "Legacy is the after-stage — what remains once the event has ended. Bidding is the before-stage, and officiating rules apply during the event, not after it."}'::jsonb),
('sport-studies:3-3-2-post-event-and-legacy:learn:b4afe60f', 'sport-studies', 'sport-studies:3-3-2-post-event-and-legacy', '3.3.2 Post-Event and Legacy', 'learn', 'mcq', 1, '{"readingTitle": "The positives: the legacy a major event can leave behind", "reading": "<h4>Facilities, transport and infrastructure</h4>\n<ul>\n<li>A host city is often left with <strong>new or upgraded sporting venues</strong> — stadiums, pools and tracks built or improved for the event that local people can keep using for years afterwards.</li>\n<li>Preparing to host often forces a city to improve its <strong>transport and social infrastructure</strong> too — new roads, rail links or wider town regeneration that outlasts the event itself.</li>\n</ul>\n<h4>Participation and profile</h4>\n<ul>\n<li>Watching a sport at a major event can inspire people to try it, so <strong>more people take part</strong> in the sports they saw — local clubs often report more new members in the years after.</li>\n<li>The same exposure can raise a sport''s <strong>profile</strong> — more media coverage, more sponsorship and more public interest than it had before the event.</li>\n</ul>\n<h4>Status and future money</h4>\n<ul>\n<li>A well-run event can leave the host with a <strong>raised international profile and status</strong> — the world now associates that place with successfully staging a huge event.</li>\n<li>That reputation can attract <strong>increased future financial investment</strong>, since businesses, tourists and future event organisers are more willing to invest once a host has proved it can deliver.</li>\n</ul>", "question": "A local swimming club reports far more new junior members two years after their city hosted a major swimming event. This is best described as...", "options": ["a rise in participation, one of the positive legacies of hosting", "clear proof that the event lost far more money than it earned", "an example of a pre-event objection raised before the bid succeeded", "evidence that the pool built for the event has become a white elephant"]}'::jsonb, '{"answer": 0, "explain": "More people taking up the sport afterwards is a participation legacy — a positive outcome, not evidence of financial loss, a bidding objection, or an unused venue."}'::jsonb),
('sport-studies:3-3-2-post-event-and-legacy:learn:63a9c303', 'sport-studies', 'sport-studies:3-3-2-post-event-and-legacy', '3.3.2 Post-Event and Legacy', 'learn', 'mcq', 1, '{"readingTitle": "The negatives: when the legacy goes wrong", "reading": "<h4>Cost versus revenue</h4>\n<ul>\n<li>Hosting is hugely expensive, and there is no guarantee the money comes back: <strong>what the event brings in can end up lower than what it cost to stage</strong>, leaving the host with a bill long after the closing ceremony.</li>\n</ul>\n<h4>''White elephants''</h4>\n<ul>\n<li>Purpose-built venues need a use afterwards. When a stadium or arena is <strong>left unused once the event is over</strong>, it is often nicknamed a <strong>''white elephant''</strong> — expensive to build and maintain, but bringing in little or no ongoing income.</li>\n<li>A venue is more likely to become a white elephant if it was built for a sport with a small local following, or if nobody planned what it would be used for after the closing ceremony.</li>\n</ul>\n<h4>Reputational loss</h4>\n<ul>\n<li>A negative legacy is not only financial. A host nation can suffer a <strong>loss of national reputation or status</strong> if the event was <strong>badly organised</strong>, if the <strong>host nation''s own athletes performed poorly</strong>, or if a <strong>scandal</strong> (for example, corruption or a doping story) emerged during or after the event.</li>\n</ul>", "question": "A purpose-built arena stands empty and unused for years after the event it was built for. What is this usually called?", "options": ["a legacy of improved social infrastructure that benefits residents", "a ''white elephant''", "a rise in participation across the sports involved", "a positive transport legacy for the host city"]}'::jsonb, '{"answer": 1, "explain": "A costly venue with no ongoing use is a ''white elephant'' — the opposite of a positive facility or transport legacy."}'::jsonb),
('sport-studies:3-3-2-post-event-and-legacy:learn:7344e00a', 'sport-studies', 'sport-studies:3-3-2-post-event-and-legacy', '3.3.2 Post-Event and Legacy', 'learn', 'mcq', 1, '{"readingTitle": "Weighing it up — the exam skill", "reading": "<h4>Legacy is rarely all good or all bad</h4>\n<ul>\n<li>Most real events produce <strong>both</strong> positives and negatives at once — a new pool that boosts participation, and an arena that stands empty, in the very same city.</li>\n<li>Weak answer: naming a single positive or a single negative in isolation. Strong answer: weighing the lasting <strong>benefits</strong> against the lasting <strong>costs</strong>, then reaching a judgement about whether the legacy was worth it overall.</li>\n</ul>\n<h4>Building a balanced answer</h4>\n<ul>\n<li>Use a scenario''s actual detail — a named facility, a stated cost, a stated rise in membership — rather than a generic point that could apply to any host city.</li>\n<li>Finish with a <strong>justified judgement</strong>: say which side of the balance is bigger, and explain why, given what the scenario shows.</li>\n</ul>", "question": "A question asks you to discuss a city''s post-event legacy. What is most likely to earn the highest marks?", "options": ["Listing every positive legacy you can remember, one after another", "Weighing lasting benefits against lasting costs and reaching a judgement", "Describing the opening ceremony of the event in as much detail as possible", "Naming only the host city, without any further detail at all"]}'::jsonb, '{"answer": 1, "explain": "Discuss/evaluate questions reward a balanced weigh-up finishing in a judgement — a one-sided list of positives, ceremony detail, or a bare name earns little."}'::jsonb),
('sport-studies:3-3-2-post-event-and-legacy:misc:dcff6c86', 'sport-studies', 'sport-studies:3-3-2-post-event-and-legacy', '3.3.2 Post-Event and Legacy', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> The ''legacy'' of hosting an event is really just whether it made a profit or a loss.</p><p><strong>✅ The correct idea:</strong> Legacy is much broader than the finances. It includes facilities (are they still used?), participation (did more people take up the sport?), profile (did the sport get more attention?), transport and infrastructure, and international status and reputation — as well as the money. A financially break-even event can still have a strong or weak legacy depending on these other factors.</p>", "question": "Which of these is part of an event''s legacy, alongside its finances?", "options": ["Only whether the event made a profit or a loss overall, once the final accounts were settled", "Facilities, participation, profile, infrastructure and reputation as well as finances", "Only the number of tickets sold on the very first day of the event", "Only the weather recorded during the opening ceremony itself"]}'::jsonb, '{"answer": 1, "explain": "Legacy covers facilities, participation, profile, infrastructure and reputation together with the finances — not the finances alone, ticket sales, or the weather."}'::jsonb),
('sport-studies:3-3-2-post-event-and-legacy:misc:ed295cdd', 'sport-studies', 'sport-studies:3-3-2-post-event-and-legacy', '3.3.2 Post-Event and Legacy', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> If a stadium is built specifically for an event, it is automatically a ''white elephant'' afterwards.</p><p><strong>✅ The correct idea:</strong> A purpose-built venue only becomes a white elephant if it is left unused once the event has finished. Plenty of purpose-built facilities go on to be busy, well-used venues for years — that is a positive facility legacy, not a white elephant. The difference is what happens to the venue AFTER the closing ceremony, not how or why it was built.</p>", "question": "What actually decides whether a purpose-built venue becomes a ''white elephant''?", "options": ["Whether it was built specifically for the event in the first place", "Whether it is left unused once the event has finished", "How expensive the venue was to construct originally", "How many spectators attended on the opening night"]}'::jsonb, '{"answer": 1, "explain": "It''s ongoing use afterwards that matters, not the fact it was purpose-built, its original cost, or opening-night attendance."}'::jsonb),
('sport-studies:3-3-2-post-event-and-legacy:misc:93e2639d', 'sport-studies', 'sport-studies:3-3-2-post-event-and-legacy', '3.3.2 Post-Event and Legacy', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Post-event legacy is only about the first few months right after the event finishes.</p><p><strong>✅ The correct idea:</strong> Legacy includes long-term effects too — a rise in participation or a facility''s popularity may only become clear years later, and a reputational or financial legacy can take just as long to settle. Judging legacy well means looking beyond the first few months.</p>", "question": "Why is it wrong to judge an event''s legacy only from its first few months?", "options": ["Because legacy includes long-term effects that may only become clear years later", "Because legacy is only ever measured in the very first month after the closing ceremony", "Because only the opening ceremony counts towards legacy", "Because legacy is decided entirely before the event even begins"]}'::jsonb, '{"answer": 0, "explain": "Legacy can take years to become clear — participation, facility use and reputation can all shift long after the first few months."}'::jsonb),
('sport-studies:3-3-2-post-event-and-legacy:misc:3db98336', 'sport-studies', 'sport-studies:3-3-2-post-event-and-legacy', '3.3.2 Post-Event and Legacy', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> One positive legacy point, like new facilities, automatically cancels out any negative legacy point, like a cost overrun.</p><p><strong>✅ The correct idea:</strong> The exam wants you to weigh both sides against each other and reach a justified judgement — not assume one positive automatically outweighs a negative, or the other way round. Sometimes a strong facility legacy genuinely outweighs a cost overrun; sometimes it doesn''t. You have to argue it using the scenario, not assume it.</p>", "question": "How should a positive legacy point and a negative legacy point be treated in a discuss/evaluate answer?", "options": ["The positive point should always be assumed to automatically cancel out any negative point in every single case", "They should be weighed against each other, with a judgement based on the scenario", "The negative point should always be assumed to win automatically, whatever the scenario shows", "Only the positive points need to be mentioned at all"]}'::jsonb, '{"answer": 1, "explain": "A good answer weighs both sides against the scenario''s actual detail and reaches a judgement — it never just assumes one side automatically wins."}'::jsonb),
('sport-studies:3-3-2-post-event-and-legacy:tips:0503c3f6', 'sport-studies', 'sport-studies:3-3-2-post-event-and-legacy', '3.3.2 Post-Event and Legacy', 'tips', 'mcq', 1, '{"readingTitle": "tip — Command words for this topic — what each one wants", "reading": "<p>Post-event and legacy questions range from quick recall to full evaluation. Match your answer length to the command word:</p>\n<ul>\n<li><strong>Identify / State</strong> — just name it. \"Identify one positive legacy\" = write one legacy, nothing more. 1 mark each.</li>\n<li><strong>Describe</strong> — say what it is or what it looks like in practice, without needing a reason.</li>\n<li><strong>Explain</strong> — give a reason, using the word <em>because</em>. \"Explain why an unused venue is a negative legacy\" = the point plus why it costs the host.</li>\n<li><strong>Discuss / Evaluate</strong> — weigh positives against negatives and give a justified judgement.</li>\n</ul>\n<p><strong>Read the mark tariff:</strong> [1] wants one point; [4] in Section B wants points applied to the scenario; [6]/[8] levelled answers want both sides plus a judgement.</p>", "question": "A question says: ''Identify one negative legacy of hosting a major event [1]''. What is the safest answer?", "options": ["A full paragraph explaining several negative legacies in detail", "One negative legacy, named", "A list of every negative legacy you can remember", "An explanation of a positive legacy instead"]}'::jsonb, '{"answer": 1, "explain": "''Identify'' + [1] = one clearly named point. A long paragraph, a long list, or the wrong side of the argument all waste time for no extra credit."}'::jsonb),
('sport-studies:3-3-2-post-event-and-legacy:tips:f0d107e4', 'sport-studies', 'sport-studies:3-3-2-post-event-and-legacy', '3.3.2 Post-Event and Legacy', 'tips', 'mcq', 1, '{"readingTitle": "tip — The golden rule: weigh the benefit against the cost", "reading": "<p>The single most common way to lose marks on this topic is answering only one side. Build longer answers as <strong>benefit vs cost, then judgement</strong>:</p>\n<ul>\n<li><strong>❌ weak:</strong> \"Hosting the event gave the city a new stadium.\" (one-sided, no weighing up)</li>\n<li><strong>✅ stronger:</strong> \"Hosting gave the city a busy new stadium, but the cost ran well over budget, so the legacy is genuinely mixed rather than simply good.\"</li>\n</ul>\n<p>In <strong>Section B and C</strong>, the question usually gives you a scenario (a named host city, a stated cost or membership figure). Use that detail directly — a generic point that could apply to any city earns less.</p>", "question": "In a scenario question about a named host city''s legacy, your answer should be built around...", "options": ["only the positive side of the argument, ignored entirely for negatives", "weighing the benefit and the cost using detail from the scenario", "a completely different event that you happen to know more about", "the opening ceremony, regardless of what the question actually asks"]}'::jsonb, '{"answer": 1, "explain": "Weighing benefit against cost, using the scenario''s own detail, is what separates a strong legacy answer from a one-sided list."}'::jsonb),
('sport-studies:3-3-2-post-event-and-legacy:tips:7c9bd7b4', 'sport-studies', 'sport-studies:3-3-2-post-event-and-legacy', '3.3.2 Post-Event and Legacy', 'tips', 'mcq', 1, '{"readingTitle": "tip — Where this appears + sentence starters", "reading": "<p><strong>Where it shows up:</strong> post-event legacy appears as quick recall in <strong>Section A</strong> (identify a positive or negative legacy), as applied points in <strong>Section B</strong> scenarios about a specific host, and it regularly feeds <strong>Section C</strong> 8-mark discuss/evaluate answers about whether hosting was \"worth it\".</p>\n<p><strong>Three punchy tips:</strong></p>\n<ul>\n<li>Learn the positives and negatives as two short lists so you can always recall at least one of each.</li>\n<li>For every point you make, tie it to a scenario detail (a named facility, a stated cost, a stated membership figure).</li>\n<li>Always end a longer answer with a judgement — don''t just stop after listing both sides.</li>\n</ul>\n<p><strong>Sentence starters for a longer answer:</strong></p>\n<ul>\n<li>\"One positive legacy here is… because…\"</li>\n<li>\"However, a negative legacy is… because…\"</li>\n<li>\"Overall, the legacy is… because…\"</li>\n</ul>", "question": "Why does a strong Section C legacy answer always finish with a judgement?", "options": ["Because a judgement is entirely optional and adds nothing at all to the final mark awarded", "Because discuss/evaluate questions reward weighing both sides and then deciding", "Because judgements replace the need to use the scenario at all", "Because only Section A questions require any kind of ending"]}'::jsonb, '{"answer": 1, "explain": "Discuss/evaluate questions are marked on balance AND judgement — stopping after listing both sides leaves the strongest mark band unreached."}'::jsonb),
('sport-studies:3-3-2-post-event-and-legacy:fib:56cba693', 'sport-studies', 'sport-studies:3-3-2-post-event-and-legacy', '3.3.2 Post-Event and Legacy', 'fib', 'fib', 1, '{"question": "The lasting effect that remains after a major event has finished is called its _____.", "blankOptions": {"B1": ["revenue", "legacy", "reputation", "participation"]}}'::jsonb, '{"blanks": {"B1": "legacy"}}'::jsonb),
('sport-studies:3-3-2-post-event-and-legacy:fib:6b47d44b', 'sport-studies', 'sport-studies:3-3-2-post-event-and-legacy', '3.3.2 Post-Event and Legacy', 'fib', 'fib', 1, '{"question": "New or upgraded stadiums that local clubs keep using for years afterwards are an example of a _____ legacy.", "blankOptions": {"B1": ["legacy", "facility", "revenue", "reputation"]}}'::jsonb, '{"blanks": {"B1": "facility"}}'::jsonb),
('sport-studies:3-3-2-post-event-and-legacy:fib:d56e257d', 'sport-studies', 'sport-studies:3-3-2-post-event-and-legacy', '3.3.2 Post-Event and Legacy', 'fib', 'fib', 1, '{"question": "A rise in the number of people trying a sport after watching it at a major event is a legacy of increased _____.", "blankOptions": {"B1": ["revenue", "unused", "facility", "participation"]}}'::jsonb, '{"blanks": {"B1": "participation"}}'::jsonb),
('sport-studies:3-3-2-post-event-and-legacy:fib:8c12cbb8', 'sport-studies', 'sport-studies:3-3-2-post-event-and-legacy', '3.3.2 Post-Event and Legacy', 'fib', 'fib', 1, '{"question": "A venue that is built for an event but then stands _____ afterwards is nicknamed a ''white elephant''.", "blankOptions": {"B1": ["unused", "facility", "revenue", "reputation"]}}'::jsonb, '{"blanks": {"B1": "unused"}}'::jsonb),
('sport-studies:3-3-2-post-event-and-legacy:fib:2c297238', 'sport-studies', 'sport-studies:3-3-2-post-event-and-legacy', '3.3.2 Post-Event and Legacy', 'fib', 'fib', 1, '{"question": "If a host nation''s event is badly organised, it can suffer a loss of national _____.", "blankOptions": {"B1": ["facility", "reputation", "revenue", "unused"]}}'::jsonb, '{"blanks": {"B1": "reputation"}}'::jsonb),
('sport-studies:3-3-2-post-event-and-legacy:fib:8d0e8ff9', 'sport-studies', 'sport-studies:3-3-2-post-event-and-legacy', '3.3.2 Post-Event and Legacy', 'fib', 'fib', 1, '{"question": "An event that costs more to host than the _____ it generates leaves the host with a financial loss.", "blankOptions": {"B1": ["facility", "participation", "reputation", "revenue"]}}'::jsonb, '{"blanks": {"B1": "revenue"}}'::jsonb),
('sport-studies:3-3-2-post-event-and-legacy:match:85962170', 'sport-studies', 'sport-studies:3-3-2-post-event-and-legacy', '3.3.2 Post-Event and Legacy', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Legacy”?", "options": ["New or improved sporting venues that continue to be used by the public after the event", "The lasting effect an event leaves behind once it has finished, which can be positive or negative", "A purpose-built venue left unused once the event it was built for has finished", "New roads, rail links or town regeneration built for the event that continue to serve the area"]}'::jsonb, '{"answer": 1, "explain": "“Legacy” means: The lasting effect an event leaves behind once it has finished, which can be positive or negative"}'::jsonb),
('sport-studies:3-3-2-post-event-and-legacy:match:0eaad141', 'sport-studies', 'sport-studies:3-3-2-post-event-and-legacy', '3.3.2 Post-Event and Legacy', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Facility legacy”?", "options": ["A city or nation being seen worldwide as capable of successfully staging a major event", "New or improved sporting venues that continue to be used by the public after the event", "A rise in the number of people taking part in the sports that featured at the event", "New roads, rail links or town regeneration built for the event that continue to serve the area"]}'::jsonb, '{"answer": 1, "explain": "“Facility legacy” means: New or improved sporting venues that continue to be used by the public after the event"}'::jsonb),
('sport-studies:3-3-2-post-event-and-legacy:match:1d700525', 'sport-studies', 'sport-studies:3-3-2-post-event-and-legacy', '3.3.2 Post-Event and Legacy', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Participation legacy”?", "options": ["Increased media coverage, sponsorship and public interest in a sport after an event", "New or improved sporting venues that continue to be used by the public after the event", "The lasting effect an event leaves behind once it has finished, which can be positive or negative", "A rise in the number of people taking part in the sports that featured at the event"]}'::jsonb, '{"answer": 3, "explain": "“Participation legacy” means: A rise in the number of people taking part in the sports that featured at the event"}'::jsonb),
('sport-studies:3-3-2-post-event-and-legacy:match:a8365b80', 'sport-studies', 'sport-studies:3-3-2-post-event-and-legacy', '3.3.2 Post-Event and Legacy', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Profile legacy”?", "options": ["Increased media coverage, sponsorship and public interest in a sport after an event", "Damage to a host nation''s standing caused by poor organisation, poor host performance or a scandal", "A rise in the number of people taking part in the sports that featured at the event", "New roads, rail links or town regeneration built for the event that continue to serve the area"]}'::jsonb, '{"answer": 0, "explain": "“Profile legacy” means: Increased media coverage, sponsorship and public interest in a sport after an event"}'::jsonb),
('sport-studies:3-3-2-post-event-and-legacy:match:c8f0a495', 'sport-studies', 'sport-studies:3-3-2-post-event-and-legacy', '3.3.2 Post-Event and Legacy', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Transport and infrastructure legacy”?", "options": ["New roads, rail links or town regeneration built for the event that continue to serve the area", "A city or nation being seen worldwide as capable of successfully staging a major event", "A rise in the number of people taking part in the sports that featured at the event", "Increased media coverage, sponsorship and public interest in a sport after an event"]}'::jsonb, '{"answer": 0, "explain": "“Transport and infrastructure legacy” means: New roads, rail links or town regeneration built for the event that continue to serve the area"}'::jsonb),
('sport-studies:3-3-2-post-event-and-legacy:match:9413a839', 'sport-studies', 'sport-studies:3-3-2-post-event-and-legacy', '3.3.2 Post-Event and Legacy', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “International status”?", "options": ["New or improved sporting venues that continue to be used by the public after the event", "A rise in the number of people taking part in the sports that featured at the event", "Increased media coverage, sponsorship and public interest in a sport after an event", "A city or nation being seen worldwide as capable of successfully staging a major event"]}'::jsonb, '{"answer": 3, "explain": "“International status” means: A city or nation being seen worldwide as capable of successfully staging a major event"}'::jsonb),
('sport-studies:3-3-2-post-event-and-legacy:match:01450a34', 'sport-studies', 'sport-studies:3-3-2-post-event-and-legacy', '3.3.2 Post-Event and Legacy', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “''White elephant''”?", "options": ["Damage to a host nation''s standing caused by poor organisation, poor host performance or a scandal", "The lasting effect an event leaves behind once it has finished, which can be positive or negative", "A purpose-built venue left unused once the event it was built for has finished", "Increased media coverage, sponsorship and public interest in a sport after an event"]}'::jsonb, '{"answer": 2, "explain": "“''White elephant''” means: A purpose-built venue left unused once the event it was built for has finished"}'::jsonb),
('sport-studies:3-3-2-post-event-and-legacy:match:a8ed8a40', 'sport-studies', 'sport-studies:3-3-2-post-event-and-legacy', '3.3.2 Post-Event and Legacy', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Reputational loss”?", "options": ["The lasting effect an event leaves behind once it has finished, which can be positive or negative", "Damage to a host nation''s standing caused by poor organisation, poor host performance or a scandal", "New or improved sporting venues that continue to be used by the public after the event", "A city or nation being seen worldwide as capable of successfully staging a major event"]}'::jsonb, '{"answer": 1, "explain": "“Reputational loss” means: Damage to a host nation''s standing caused by poor organisation, poor host performance or a scandal"}'::jsonb),
('sport-studies:4-1-the-role-of-ngbs:exam:2b6ca6d0', 'sport-studies', 'sport-studies:4-1-the-role-of-ngbs', '4.1 The Role of NGBs', 'exam', 'mcq', 1, '{"num": "2", "question": "Which of these is a genuine role of a National Governing Body (NGB)?", "options": ["Selling television advertising space during a live international fixture", "Training and qualifying coaches and officials through a system of levels", "Deciding which players a private club should sign each transfer window", "Setting the ticket price for a single local five-a-side tournament"], "hint": "Think about which option matches building up the sport''s coaching and officiating infrastructure.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: B — Training and qualifying coaches and officials through a system of levels.</strong></p>\n<ul>\n<li>This is the NGB''s coaching and officiating infrastructure role.</li>\n<li>TV advertising, club transfers and one local event''s pricing are not NGB roles.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('sport-studies:4-1-the-role-of-ngbs:mcq:689f65d9', 'sport-studies', 'sport-studies:4-1-the-role-of-ngbs', '4.1 The Role of NGBs', 'mcq', 'mcq', 1, '{"question": "What is the main purpose of a National Governing Body (NGB)?", "options": ["To run and develop a single sport nationally, from grassroots to elite level", "To sell official replica kit and matchday merchandise for one sport''s national team", "To broadcast every fixture in a sport live to a subscription-only audience", "To organise one single local competition, held once a year in one town"]}'::jsonb, '{"answer": 0, "explain": "An NGB runs and develops its whole sport nationally, across every level — not merchandise, broadcasting rights, or a single yearly event."}'::jsonb),
('sport-studies:4-1-the-role-of-ngbs:mcq:691da779', 'sport-studies', 'sport-studies:4-1-the-role-of-ngbs', '4.1 The Role of NGBs', 'mcq', 'mcq', 1, '{"question": "Why might an NGB run a scheme that specifically targets an under-represented group, such as girls or older beginners?", "options": ["To meet a legal quota requiring exactly equal numbers of people from every group", "To grow the sport by giving equal opportunities to groups who are not yet taking part", "To reduce overall participation numbers so that facilities stay quieter", "To guarantee that this particular group wins every regional competition it enters this season"]}'::jsonb, '{"answer": 1, "explain": "Targeted schemes widen participation by removing the barriers a specific group faces — they are not about quotas, quieter facilities, or guaranteed wins."}'::jsonb),
('sport-studies:4-1-the-role-of-ngbs:mcq:dbd7d35e', 'sport-studies', 'sport-studies:4-1-the-role-of-ngbs', '4.1 The Role of NGBs', 'mcq', 'mcq', 1, '{"question": "An NGB runs a Level 1 coaching award and trains new referees through a levels system. What is this an example of?", "options": ["Lobbying central government for extra funding for elite facilities", "Applying disciplinary procedures against a professional club", "Developing the sport''s coaching and officiating infrastructure", "Organising the national team''s fixtures for the coming season"]}'::jsonb, '{"answer": 2, "explain": "Coaching awards and refereeing levels build up the sport''s coaching and officiating infrastructure — not funding, discipline, or fixture-organising."}'::jsonb),
('sport-studies:4-1-the-role-of-ngbs:mcq:36e82116', 'sport-studies', 'sport-studies:4-1-the-role-of-ngbs', '4.1 The Role of NGBs', 'mcq', 'mcq', 1, '{"question": "A club is fined and a player is suspended after a serious breach of the rules. Which NGB role is being shown here?", "options": ["Providing detailed technical guidance and coaching resources to affiliated members", "Promoting participation through a national media campaign", "Organising a tournament for the sport''s top regional teams", "Amending the rules and applying disciplinary procedures for rule-breaking"]}'::jsonb, '{"answer": 3, "explain": "A fine and a suspension show disciplinary procedures being applied — the guidance, promotion and tournament options describe different NGB jobs."}'::jsonb),
('sport-studies:4-1-the-role-of-ngbs:mcq:0ff03443', 'sport-studies', 'sport-studies:4-1-the-role-of-ngbs', '4.1 The Role of NGBs', 'mcq', 'mcq', 1, '{"question": "A local club asks its NGB for advice on running sessions safely and for insurance cover. Which role is this?", "options": ["Lobbying government bodies for extra grassroots funding", "Providing support, insurance and technical guidance to members", "Organising national and regional competitions for the sport", "Developing a brand-new policy on player welfare and safeguarding"]}'::jsonb, '{"answer": 1, "explain": "Advice and insurance cover for an affiliated club are exactly what the support, insurance and technical guidance role covers."}'::jsonb),
('sport-studies:4-1-the-role-of-ngbs:mcq:b970d332', 'sport-studies', 'sport-studies:4-1-the-role-of-ngbs', '4.1 The Role of NGBs', 'mcq', 'mcq', 1, '{"question": "An NGB spends time formally arguing its case to government for more investment in facilities and coaching. What is this called?", "options": ["Ensuring safety within the sport at every level of competition", "Applying disciplinary procedures for serious rule-breaking", "Lobbying for funding to invest in the sport", "Developing new policies and initiatives for its members"]}'::jsonb, '{"answer": 2, "explain": "Formally arguing the case to government or funding bodies for investment is lobbying for funding — a different job from safety, discipline or policy-writing."}'::jsonb),
('sport-studies:4-1-the-role-of-ngbs:tf:b6700626', 'sport-studies', 'sport-studies:4-1-the-role-of-ngbs', '4.1 The Role of NGBs', 'tf', 'tf', 1, '{"question": "A National Governing Body is responsible for running and developing one sport nationally."}'::jsonb, '{"answer": true, "explain": "That''s the definition of an NGB — one official organisation overseeing its sport from grassroots to elite level."}'::jsonb),
('sport-studies:4-1-the-role-of-ngbs:tf:9c5bb691', 'sport-studies', 'sport-studies:4-1-the-role-of-ngbs', '4.1 The Role of NGBs', 'tf', 'tf', 1, '{"question": "An NGB has no involvement in training referees or officials — clubs are left to sort that out alone."}'::jsonb, '{"answer": false, "explain": "NGBs design and run officiating qualifications through levels, so officials at every level of the sport are properly trained."}'::jsonb),
('sport-studies:4-1-the-role-of-ngbs:tf:12b2c9e5', 'sport-studies', 'sport-studies:4-1-the-role-of-ngbs', '4.1 The Role of NGBs', 'tf', 'tf', 1, '{"question": "An NGB can amend (change) the rules of its own sport when it needs to."}'::jsonb, '{"answer": true, "explain": "NGBs own the official rulebook and can change it, for example to improve safety or close a loophole."}'::jsonb),
('sport-studies:4-1-the-role-of-ngbs:tf:4bad40d3', 'sport-studies', 'sport-studies:4-1-the-role-of-ngbs', '4.1 The Role of NGBs', 'tf', 'tf', 1, '{"question": "Because NGBs never target under-represented groups, every session is aimed at exactly the same audience."}'::jsonb, '{"answer": false, "explain": "Promoting participation includes running schemes for under-represented groups, such as girls or older beginners, to widen who takes part."}'::jsonb),
('sport-studies:4-1-the-role-of-ngbs:tf:3a8ffa0e', 'sport-studies', 'sport-studies:4-1-the-role-of-ngbs', '4.1 The Role of NGBs', 'tf', 'tf', 1, '{"question": "Lobbying for funding means an NGB formally argues its case to government or other funding bodies for investment."}'::jsonb, '{"answer": true, "explain": "That''s exactly what lobbying means here — making the case for money to invest in facilities, coaching and development."}'::jsonb),
('sport-studies:4-1-the-role-of-ngbs:tf:1d9d9b9e', 'sport-studies', 'sport-studies:4-1-the-role-of-ngbs', '4.1 The Role of NGBs', 'tf', 'tf', 1, '{"question": "Because clubs run their own sessions, an NGB never sets safety standards for facilities or equipment."}'::jsonb, '{"answer": false, "explain": "Ensuring safety is a core NGB role — it sets minimum safety standards that affiliated clubs and coaches are expected to follow."}'::jsonb),
('sport-studies:4-1-the-role-of-ngbs:learn:9a730c93', 'sport-studies', 'sport-studies:4-1-the-role-of-ngbs', '4.1 The Role of NGBs', 'learn', 'mcq', 1, '{"readingTitle": "What a National Governing Body (NGB) is", "reading": "<h4>The idea</h4>\n<ul>\n<li>A <strong>National Governing Body (NGB)</strong> is the official organisation put in charge of running and developing one sport across the whole country.</li>\n<li>Every major sport in the UK has its own NGB — for example, there is a national governing body for football, one for rugby union, one for swimming and one for tennis. Each one oversees its sport from complete beginners right up to the national team.</li>\n</ul>\n<h4>What NGBs are actually for</h4>\n<ul>\n<li>An NGB is not just a name on a badge — it carries out a wide range of jobs that keep its sport running, growing and fair.</li>\n<li>The exam does not want you to simply name what an NGB does; it wants you to explain the <strong>purpose</strong> behind each role — what the NGB does, and <em>why</em> that helps the sport.</li>\n<li>Build a habit of turning every role into a \"so that\" sentence: \"an NGB runs coaching qualifications <strong>so that</strong> more good coaches come through, which raises the standard of the sport.\"</li>\n</ul>", "question": "Which of these best describes what a National Governing Body (NGB) is?", "options": ["The official organisation in charge of running and developing one sport nationally", "A private company that manufactures and sells replica kit for one sport''s fans", "A local leisure centre that runs a single weekly beginners'' session for one particular sport", "A supporters'' group that arranges travel to a national team''s away fixtures"]}'::jsonb, '{"answer": 0, "explain": "An NGB is the official body overseeing a whole sport nationally — not a kit manufacturer, a single venue, or a supporters'' group."}'::jsonb),
('sport-studies:4-1-the-role-of-ngbs:learn:21b4fcf7', 'sport-studies', 'sport-studies:4-1-the-role-of-ngbs', '4.1 The Role of NGBs', 'learn', 'mcq', 1, '{"readingTitle": "Growing the sport: participation, coaching and competitions", "reading": "<h4>Promoting participation</h4>\n<ul>\n<li>NGBs run schemes and campaigns to get more people playing their sport — for example, running a taster scheme in schools, or advertising through the media to reach new audiences.</li>\n<li>Part of this job is making sure the sport offers <strong>equal opportunities</strong> — actively encouraging groups who are currently under-represented, such as girls, disabled players or older beginners, so the sport grows rather than staying with the same small audience.</li>\n</ul>\n<h4>Developing coaching and officiating</h4>\n<ul>\n<li>An NGB designs and runs <strong>coaching qualifications</strong>, usually organised into levels — for instance a Level 1 award for a helper, up to advanced awards for coaching representative teams.</li>\n<li>It does the same for <strong>officiating</strong> — training and qualifying referees, umpires or judges through levels — so that games at every level are run by people who know the rules properly.</li>\n<li><strong>Why this matters:</strong> without a steady supply of qualified coaches and officials, clubs cannot run new sessions or fixtures, so the sport cannot grow.</li>\n</ul>\n<h4>Organising tournaments and competitions</h4>\n<ul>\n<li>NGBs organise the fixture list and competition structure for their sport — from local leagues, through regional and national cups, up to the national representative team''s matches.</li>\n<li>This gives performers of every standard somewhere to test themselves and something to aim for, which keeps people motivated to keep training and playing.</li>\n</ul>", "question": "An NGB trains and qualifies referees through a system of levels. Which NGB role does this show?", "options": ["Lobbying central government for extra funding for elite facilities", "Developing the sport''s coaching and officiating infrastructure", "Applying disciplinary procedures against a professional club", "Organising the national representative team''s next fixture list"]}'::jsonb, '{"answer": 1, "explain": "Training and qualifying officials through levels is part of developing coaching and officiating infrastructure — not funding, discipline, or fixtures on their own."}'::jsonb),
('sport-studies:4-1-the-role-of-ngbs:learn:36e82116', 'sport-studies', 'sport-studies:4-1-the-role-of-ngbs', '4.1 The Role of NGBs', 'learn', 'mcq', 1, '{"readingTitle": "Keeping the sport fair and safe: rules, discipline and safety", "reading": "<h4>Amending rules and applying discipline</h4>\n<ul>\n<li>An NGB owns the official rulebook for its sport and can <strong>amend (change) the rules</strong> when it needs to — for example to make a contact sport safer, or to close a loophole players are exploiting.</li>\n<li>When a player, coach or club breaks the rules, the NGB applies its <strong>disciplinary procedures</strong> — this can mean a warning, a fine, a suspension, or in serious cases a much longer ban.</li>\n<li><strong>Purpose:</strong> without a body willing to enforce the rules, breaking them would carry no real consequence, and the sport would stop being fair for everyone else taking part.</li>\n</ul>\n<h4>Ensuring safety</h4>\n<ul>\n<li>NGBs set minimum safety standards for equipment, facilities and how sessions are run, and expect affiliated clubs and coaches to follow them.</li>\n<li>They may also set rules around player welfare — for instance concussion protocols in contact sports — so participants are protected from unnecessary injury.</li>\n</ul>\n<h4>Support, insurance and technical guidance</h4>\n<ul>\n<li>NGBs provide <strong>support</strong> to their affiliated clubs and members, such as advice on running a club or a helpline for questions.</li>\n<li>Many arrange or require <strong>insurance</strong> cover, so that clubs, coaches and players are protected if an accident happens during the sport.</li>\n<li>They also give <strong>technical guidance</strong> — coaching resources, skill breakdowns and best-practice advice — so members do not have to work everything out for themselves.</li>\n</ul>", "question": "A club is fined and a player is suspended after a serious breach of the rules. Which NGB role is being shown here?", "options": ["Providing detailed technical guidance and coaching resources to affiliated members", "Promoting participation through a national media campaign", "Organising a tournament for the sport''s top regional teams", "Amending the rules and applying disciplinary procedures for rule-breaking"]}'::jsonb, '{"answer": 3, "explain": "A fine and a suspension are disciplinary procedures being applied after the rules were broken — not guidance, promotion, or fixture organisation."}'::jsonb),
('sport-studies:4-1-the-role-of-ngbs:learn:7f6cf54b', 'sport-studies', 'sport-studies:4-1-the-role-of-ngbs', '4.1 The Role of NGBs', 'learn', 'mcq', 1, '{"readingTitle": "Steering the sport''s future: policies, funding — and the exam skill", "reading": "<h4>Developing policies and initiatives</h4>\n<ul>\n<li>An NGB writes <strong>policies</strong> — official written plans covering things like safeguarding, anti-discrimination or long-term development — that clubs and members are expected to follow.</li>\n<li>It also launches <strong>initiatives</strong> — new projects designed to solve a specific problem the sport faces, such as a shortage of coaches in one region or falling participation among one user group.</li>\n</ul>\n<h4>Lobbying for funding</h4>\n<ul>\n<li>NGBs <strong>lobby</strong> (formally argue their case to) government bodies and other funding organisations for money to invest in facilities, coaching and grassroots development.</li>\n<li>Extra funding lets an NGB build or improve facilities, subsidise coaching courses, or fund talent pathways — all of which grow and improve the sport over time.</li>\n</ul>\n<h4>Naming a role is only the start</h4>\n<ul>\n<li>Weak answer: <em>\"An NGB organises competitions.\"</em> That names a role but shows no real understanding.</li>\n<li>Strong answer: <em>\"An NGB organises competitions at every level, so that players of all abilities have a clear pathway and stay motivated to keep training.\"</em></li>\n<li>Whichever role you are asked about, build your answer as <strong>role → what it involves → why it helps the sport</strong>.</li>\n</ul>", "question": "A question asks you to explain how an NGB lobbies for funding. What is most likely to earn full marks?", "options": ["Just naming ''lobbying for funding'' with no further detail at all", "Saying the NGB argues for funding, and explaining what that funding is then used for", "Listing every other NGB role you can possibly remember, in as much detail as possible", "Describing how a private sponsor pays one professional athlete''s wages"]}'::jsonb, '{"answer": 1, "explain": "Naming plus what the funding achieves (facilities, coaching, pathways) shows the understanding the mark scheme rewards — naming alone, or listing unrelated roles, does not."}'::jsonb),
('sport-studies:4-1-the-role-of-ngbs:misc:ec93e09c', 'sport-studies', 'sport-studies:4-1-the-role-of-ngbs', '4.1 The Role of NGBs', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Explaining an NGB''s role just means naming what it does, like ''organises competitions''.</p><p><strong>✅ The correct idea:</strong> Naming is only the first mark at most. The examiner wants you to link the role to its purpose. Weak answer: \"An NGB organises competitions.\" Full-marks answer: \"An NGB organises competitions at every level, so that players of all abilities have a clear pathway and stay motivated to keep training.\" The difference is the reason.</p>", "question": "An ''Explain'' question asks about one NGB role. What earns the marks?", "options": ["Naming as many different NGB roles as you possibly can, quickly", "Naming the role, then explaining why it helps the sport", "Writing the role''s name in capital letters", "Describing your own favourite sporting event in detail"]}'::jsonb, '{"answer": 1, "explain": "Explain = point + reason. Naming the role alone, or listing several roles, does not show the understanding the mark scheme rewards."}'::jsonb),
('sport-studies:4-1-the-role-of-ngbs:misc:2d5cb3da', 'sport-studies', 'sport-studies:4-1-the-role-of-ngbs', '4.1 The Role of NGBs', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> An NGB only deals with the best professional players and elite competitions.</p><p><strong>✅ The correct idea:</strong> An NGB oversees its ENTIRE sport, not only the elite end. The same organisation that runs the national team''s fixtures also sets up beginner coaching levels, safety standards for a small local club, and insurance advice for grassroots members. ''National'' means the whole country and every level, not just the top.</p>", "question": "Which of these best shows the true scope of an NGB''s work?", "options": ["Running only the national representative team''s own annual fixture list", "Overseeing the sport from grassroots beginners up to elite level", "Managing only the training of already-professional athletes", "Advising a single elite club on its transfer policy"]}'::jsonb, '{"answer": 1, "explain": "An NGB''s roles — coaching, safety, competitions, support — apply across the whole sport, from complete beginners through to the national team."}'::jsonb),
('sport-studies:4-1-the-role-of-ngbs:misc:ed82aa9b', 'sport-studies', 'sport-studies:4-1-the-role-of-ngbs', '4.1 The Role of NGBs', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> ''Lobbying for funding'' means the NGB hands out money to clubs itself, like a bank.</p><p><strong>✅ The correct idea:</strong> Lobbying is arguing the CASE for funding to somebody else — usually government or another funding body — not giving money out directly. The NGB persuades others to invest, and then uses any funding it secures to improve facilities, coaching and development.</p>", "question": "What does ''lobbying for funding'' actually involve?", "options": ["The NGB directly paying every affiliated club from its own bank account each year", "The NGB formally arguing its case to government or funding bodies for investment", "The NGB refusing to accept any outside investment at all", "The NGB selling shares in the sport to private investors"]}'::jsonb, '{"answer": 1, "explain": "Lobbying means making the case for investment to an outside body — it is not the NGB acting as a bank and handing out its own money."}'::jsonb),
('sport-studies:4-1-the-role-of-ngbs:misc:ee786721', 'sport-studies', 'sport-studies:4-1-the-role-of-ngbs', '4.1 The Role of NGBs', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Ensuring safety and applying disciplinary procedures are really just the same NGB role.</p><p><strong>✅ The correct idea:</strong> They are related but different. Ensuring safety is about setting standards BEFORE anything goes wrong (equipment, facilities, welfare rules). Applying disciplinary procedures is about punishing rule-breaking AFTER it has already happened (fines, suspensions, bans). A question can ask about either, so keep them separate in your answer.</p>", "question": "Which of these is part of ''ensuring safety'', rather than ''discipline''?", "options": ["Suspending a player from every competitive fixture for a full six months", "Fining a club for a rule-breaking incident", "Setting minimum safety standards for all equipment before sessions begin", "Banning a coach for repeated rule violations"]}'::jsonb, '{"answer": 2, "explain": "Setting standards before anything goes wrong is safety; fines, suspensions and bans are all discipline applied after a rule has been broken."}'::jsonb),
('sport-studies:4-1-the-role-of-ngbs:tips:4ee5c8e8', 'sport-studies', 'sport-studies:4-1-the-role-of-ngbs', '4.1 The Role of NGBs', 'tips', 'mcq', 1, '{"readingTitle": "tip — Command words for this topic — what each one wants", "reading": "<p>NGB questions are usually short recall or applied questions. Match your answer length to the command word:</p>\n<ul>\n<li><strong>Identify / State</strong> — just name it. \"Identify two roles of an NGB\" = two role names, nothing more. 1 mark each.</li>\n<li><strong>Describe</strong> — say what the role involves. \"Describe how an NGB supports coaching\" = give the features of that role.</li>\n<li><strong>Explain</strong> — give a reason. Use the word <em>because</em> or <em>so that</em>. \"Explain why an NGB applies disciplinary procedures\" = the role <em>plus</em> why it matters.</li>\n</ul>\n<p><strong>Read the mark tariff:</strong> [1] wants one point; [2]-[4] usually wants points developed or applied to a scenario; a levelled 6/8-mark question wants a balanced, judged answer.</p>", "question": "A question says: ''Identify two roles of a National Governing Body [2]''. What is the safest answer?", "options": ["A long paragraph about one role", "Two role names", "One role name explained in detail", "A list of six roles"]}'::jsonb, '{"answer": 1, "explain": "''Identify'' + [2] = two names, one mark each. Explaining one role, or listing six, wastes time and risks the examiner marking only the first two anyway."}'::jsonb),
('sport-studies:4-1-the-role-of-ngbs:tips:cdcb04ca', 'sport-studies', 'sport-studies:4-1-the-role-of-ngbs', '4.1 The Role of NGBs', 'tips', 'mcq', 1, '{"readingTitle": "tip — The golden rule: name the role AND its purpose", "reading": "<p>The single most common way to lose marks here is stopping at the name. Build every answer as <strong>role → purpose</strong>:</p>\n<ul>\n<li><strong>❌ 0–1 marks:</strong> \"It organises competitions.\"</li>\n<li><strong>✅ full marks:</strong> \"It organises competitions at every level, so players of all abilities have a pathway and stay motivated.\"</li>\n</ul>\n<p>In <strong>Section B</strong> the question gives you a scenario (a named club, a named problem). You must then use a detail <em>from that scenario</em>, not a general example.</p>", "question": "In a Section B scenario question about a named club''s problem, your example should come from...", "options": ["absolutely any sport that you happen to like", "the scenario you are given", "a famous athlete", "your own school only"]}'::jsonb, '{"answer": 1, "explain": "Section B is applied — the marks are for using the scenario in front of you. A general example that ignores the scenario is capped."}'::jsonb),
('sport-studies:4-1-the-role-of-ngbs:tips:f0d7cef1', 'sport-studies', 'sport-studies:4-1-the-role-of-ngbs', '4.1 The Role of NGBs', 'tips', 'mcq', 1, '{"readingTitle": "tip — Where NGB roles appear + sentence starters", "reading": "<p><strong>Where it shows up:</strong> NGB roles appear as quick recall in <strong>Section A</strong> (identify/state), and as applied points in <strong>Section B</strong> scenarios about a club''s problem. They also feed <strong>Section C</strong> 8-mark answers about how effectively an NGB balances growing a sport with policing it.</p>\n<p><strong>Three punchy tips:</strong></p>\n<ul>\n<li>Learn the roles in pairs (growth roles: participation, coaching, competitions, policies, funding; policing roles: rules, discipline, safety, support) so you can always recall a few from each side.</li>\n<li>For every role, memorise <em>one</em> reason it helps the sport — that reason is usually where the mark is.</li>\n<li>Watch for the link between roles: weak discipline can undo good promotion work, which is a great evaluation point.</li>\n</ul>\n<p><strong>Sentence starters for a longer answer:</strong></p>\n<ul>\n<li>\"One way an NGB develops the sport is… which helps because…\"</li>\n<li>\"On the policing side, the NGB…\"</li>\n<li>\"However, a limit of this is…\"</li>\n</ul>", "question": "Why is the link between ''growth'' roles and ''policing'' roles a useful evaluation point?", "options": ["It fills space", "It shows the two sides of an NGB''s work can affect each other", "It means NGBs do not really need rules", "It completely replaces the need to name any individual roles at all"]}'::jsonb, '{"answer": 1, "explain": "Noticing that weak discipline can undermine participation growth (or vice versa) shows deeper understanding — the kind of point that lifts a Section C answer."}'::jsonb),
('sport-studies:4-1-the-role-of-ngbs:fib:804b636f', 'sport-studies', 'sport-studies:4-1-the-role-of-ngbs', '4.1 The Role of NGBs', 'fib', 'fib', 1, '{"question": "A National Governing Body is the organisation officially in charge of running and _____ a single sport nationally.", "blankOptions": {"B1": ["insurance", "disciplinary", "developing", "lobby"]}}'::jsonb, '{"blanks": {"B1": "developing"}}'::jsonb),
