('sport-studies:4-1-the-role-of-ngbs:fib:6348468a', 'sport-studies', 'sport-studies:4-1-the-role-of-ngbs', '4.1 The Role of NGBs', 'fib', 'fib', 1, '{"question": "NGBs _____ government and other funding bodies for investment in facilities and coaching.", "blankOptions": {"B1": ["developing", "lobby", "participation", "insurance"]}}'::jsonb, '{"blanks": {"B1": "lobby"}}'::jsonb),
('sport-studies:4-1-the-role-of-ngbs:match:a60d0610', 'sport-studies', 'sport-studies:4-1-the-role-of-ngbs', '4.1 The Role of NGBs', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “National Governing Body (NGB)”?", "options": ["Writing official plans, launching new projects, and arguing the sport''s case for investment", "Changing the rulebook when needed, and punishing players or clubs who break the rules", "The official organisation in charge of running and developing one sport across the whole country", "Running schemes and media campaigns so more people, including under-represented groups, start taking part"]}'::jsonb, '{"answer": 2, "explain": "“National Governing Body (NGB)” means: The official organisation in charge of running and developing one sport across the whole country"}'::jsonb),
('sport-studies:4-1-the-role-of-ngbs:match:00c498bc', 'sport-studies', 'sport-studies:4-1-the-role-of-ngbs', '4.1 The Role of NGBs', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Promoting participation”?", "options": ["Helping affiliated clubs with advice, insurance cover and coaching resources", "Running schemes and media campaigns so more people, including under-represented groups, start taking part", "Designing and running qualification levels for coaches and for referees, umpires or judges", "Writing official plans, launching new projects, and arguing the sport''s case for investment"]}'::jsonb, '{"answer": 1, "explain": "“Promoting participation” means: Running schemes and media campaigns so more people, including under-represented groups, start taking part"}'::jsonb),
('sport-studies:4-1-the-role-of-ngbs:match:cc60b068', 'sport-studies', 'sport-studies:4-1-the-role-of-ngbs', '4.1 The Role of NGBs', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Coaching and officiating infrastructure”?", "options": ["Changing the rulebook when needed, and punishing players or clubs who break the rules", "Designing and running qualification levels for coaches and for referees, umpires or judges", "Running schemes and media campaigns so more people, including under-represented groups, start taking part", "Setting up the leagues, cups and fixtures that give performers of every standard somewhere to compete"]}'::jsonb, '{"answer": 1, "explain": "“Coaching and officiating infrastructure” means: Designing and running qualification levels for coaches and for referees, umpires or judges"}'::jsonb),
('sport-studies:4-1-the-role-of-ngbs:match:06387c0a', 'sport-studies', 'sport-studies:4-1-the-role-of-ngbs', '4.1 The Role of NGBs', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Organising tournaments and competitions”?", "options": ["Writing official plans, launching new projects, and arguing the sport''s case for investment", "The official organisation in charge of running and developing one sport across the whole country", "Setting up the leagues, cups and fixtures that give performers of every standard somewhere to compete", "Helping affiliated clubs with advice, insurance cover and coaching resources"]}'::jsonb, '{"answer": 2, "explain": "“Organising tournaments and competitions” means: Setting up the leagues, cups and fixtures that give performers of every standard somewhere to compete"}'::jsonb),
('sport-studies:4-1-the-role-of-ngbs:match:5ab6120c', 'sport-studies', 'sport-studies:4-1-the-role-of-ngbs', '4.1 The Role of NGBs', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Amending rules and applying disciplinary procedures”?", "options": ["Running schemes and media campaigns so more people, including under-represented groups, start taking part", "Changing the rulebook when needed, and punishing players or clubs who break the rules", "Helping affiliated clubs with advice, insurance cover and coaching resources", "Setting up the leagues, cups and fixtures that give performers of every standard somewhere to compete"]}'::jsonb, '{"answer": 1, "explain": "“Amending rules and applying disciplinary procedures” means: Changing the rulebook when needed, and punishing players or clubs who break the rules"}'::jsonb),
('sport-studies:4-1-the-role-of-ngbs:match:78b57047', 'sport-studies', 'sport-studies:4-1-the-role-of-ngbs', '4.1 The Role of NGBs', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Ensuring safety”?", "options": ["Helping affiliated clubs with advice, insurance cover and coaching resources", "Writing official plans, launching new projects, and arguing the sport''s case for investment", "Setting minimum safety standards for equipment, facilities and how sessions are run", "Changing the rulebook when needed, and punishing players or clubs who break the rules"]}'::jsonb, '{"answer": 2, "explain": "“Ensuring safety” means: Setting minimum safety standards for equipment, facilities and how sessions are run"}'::jsonb),
('sport-studies:4-1-the-role-of-ngbs:match:b98a0f56', 'sport-studies', 'sport-studies:4-1-the-role-of-ngbs', '4.1 The Role of NGBs', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Support, insurance and technical guidance”?", "options": ["Helping affiliated clubs with advice, insurance cover and coaching resources", "Running schemes and media campaigns so more people, including under-represented groups, start taking part", "Changing the rulebook when needed, and punishing players or clubs who break the rules", "Setting up the leagues, cups and fixtures that give performers of every standard somewhere to compete"]}'::jsonb, '{"answer": 0, "explain": "“Support, insurance and technical guidance” means: Helping affiliated clubs with advice, insurance cover and coaching resources"}'::jsonb),
('sport-studies:4-1-the-role-of-ngbs:match:b2309dc8', 'sport-studies', 'sport-studies:4-1-the-role-of-ngbs', '4.1 The Role of NGBs', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Policies, initiatives and lobbying for funding”?", "options": ["Setting up the leagues, cups and fixtures that give performers of every standard somewhere to compete", "The official organisation in charge of running and developing one sport across the whole country", "Writing official plans, launching new projects, and arguing the sport''s case for investment", "Running schemes and media campaigns so more people, including under-represented groups, start taking part"]}'::jsonb, '{"answer": 2, "explain": "“Policies, initiatives and lobbying for funding” means: Writing official plans, launching new projects, and arguing the sport''s case for investment"}'::jsonb),
('sport-studies:5-1-1-technology-to-enhance-performance:exam:e070f2a2', 'sport-studies', 'sport-studies:5-1-1-technology-to-enhance-performance', '5.1.1 Technology to Enhance Performance', 'exam', 'mcq', 1, '{"num": "2", "question": "Which of these is an example of technology used to <strong>enhance performance</strong>?", "options": ["A big screen inside the stadium that replays a controversial decision for the crowd", "A GPS vest that records a footballer''s distance and sprint speed in training", "A padded headguard that protects a boxer during a sparring session", "A video-review system that helps a match official confirm a close decision"], "hint": "Think about which option is about improving performance, not safety, officiating or spectators.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: B — A GPS vest that records a footballer''s distance and sprint speed in training.</strong></p>\n<ul>\n<li>GPS data is used to inform training decisions and improve performance.</li>\n<li>The big screen, headguard and video-review system are spectator, safety and officiating technology — covered elsewhere.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('sport-studies:5-1-1-technology-to-enhance-performance:mcq:9db04161', 'sport-studies', 'sport-studies:5-1-1-technology-to-enhance-performance', '5.1.1 Technology to Enhance Performance', 'mcq', 'mcq', 1, '{"question": "A time-trial cyclist wears a one-piece skinsuit and an aero helmet. What is this designed to do?", "options": ["Reduce air resistance so the cyclist can hold a faster speed for the same effort", "Make it easier for television commentators to identify which team the rider is racing for", "Meet a strict minimum-weight rule set out by the event''s national governing body", "Keep the cyclist noticeably warmer during a long, cold winter training ride outdoors"]}'::jsonb, '{"answer": 0, "explain": "A skinsuit and aero helmet cut air resistance, letting the cyclist hold a faster speed for the same effort — identification, weight rules and warmth are not the purpose."}'::jsonb),
('sport-studies:5-1-1-technology-to-enhance-performance:mcq:563397a2', 'sport-studies', 'sport-studies:5-1-1-technology-to-enhance-performance', '5.1.1 Technology to Enhance Performance', 'mcq', 'mcq', 1, '{"question": "Why might a badminton player choose a modern carbon-fibre racket over an old wooden one?", "options": ["It is heavier overall, which helps generate much more power on every single shot played", "It is lighter and stiffer, giving more power and control with less arm fatigue", "It is the only racket type that badminton''s national governing body allows in competition", "It is made from the same dense wood that professional rackets always used in the past"]}'::jsonb, '{"answer": 1, "explain": "Carbon fibre is lighter and stiffer than wood, giving more power and control with less fatigue. It is not heavier, not the only legal type, and not the same material as before."}'::jsonb),
('sport-studies:5-1-1-technology-to-enhance-performance:mcq:b4b8ff49', 'sport-studies', 'sport-studies:5-1-1-technology-to-enhance-performance', '5.1.1 Technology to Enhance Performance', 'mcq', 'mcq', 1, '{"question": "Which feature of modern running shoes helps some runners push off the ground with less wasted effort?", "options": ["A heavier sole added purely to increase the overall stability of the shoe", "An extra-wide sole shaped only to make the shoe more comfortable to walk in", "A cushioned, energy-returning sole, sometimes with a stiff supportive plate", "A plain rubber sole identical to the design used in football boots decades ago"]}'::jsonb, '{"answer": 2, "explain": "A cushioned, energy-returning sole reduces wasted effort on push-off. Extra weight, comfort-only width and an old plain design do not give this performance benefit."}'::jsonb),
('sport-studies:5-1-1-technology-to-enhance-performance:mcq:bd20ce93', 'sport-studies', 'sport-studies:5-1-1-technology-to-enhance-performance', '5.1.1 Technology to Enhance Performance', 'mcq', 'mcq', 1, '{"question": "A rugby coach studies a player''s GPS data from a match. What is this mainly used for?", "options": ["To broadcast the player''s exact position live to spectators in the crowd around the pitch", "To decide automatically which player should be sent off for an unsafe, high tackle", "To replace the referee''s decisions on foul play during the whole ninety minutes", "To see how much distance and effort the player covered, to plan future training"]}'::jsonb, '{"answer": 3, "explain": "GPS data mainly shows distance and effort so the coach can plan training — it does not broadcast positions, send players off, or replace refereeing decisions."}'::jsonb),
('sport-studies:5-1-1-technology-to-enhance-performance:mcq:8a6acde0', 'sport-studies', 'sport-studies:5-1-1-technology-to-enhance-performance', '5.1.1 Technology to Enhance Performance', 'mcq', 'mcq', 1, '{"question": "A swimming coach films a swimmer''s stroke and slows the footage down frame by frame. Why?", "options": ["To check the swimmer''s racing suit matches the exact colour of their team''s kit", "To spot a technical fault in the stroke that the swimmer cannot feel themselves", "To measure how loudly the crowd is cheering for that swimmer during the race", "To confirm the swimming pool itself is exactly the regulation length required"]}'::jsonb, '{"answer": 1, "explain": "Slowed footage lets a coach spot a technical fault the swimmer cannot feel — kit colour, crowd noise and pool length are unrelated to this use of video."}'::jsonb),
('sport-studies:5-1-1-technology-to-enhance-performance:mcq:f31f3fe0', 'sport-studies', 'sport-studies:5-1-1-technology-to-enhance-performance', '5.1.1 Technology to Enhance Performance', 'mcq', 'mcq', 1, '{"question": "Why do some elite sprinters wear tight-fitting, lightweight racing suits rather than loose training kit?", "options": ["Loose kit is banned completely under global athletics competition clothing rules", "Tight kit is required so photo-finish cameras can read the sprinter''s race number", "Tight, lightweight kit reduces air resistance over the short, explosive race", "Tight kit keeps the sprinter''s whole body noticeably warmer throughout the race"]}'::jsonb, '{"answer": 2, "explain": "Tight, lightweight kit reduces air resistance over a short sprint, aiding speed — it is not about a ban, reading race numbers, or keeping warm."}'::jsonb),
('sport-studies:5-1-1-technology-to-enhance-performance:tf:df064351', 'sport-studies', 'sport-studies:5-1-1-technology-to-enhance-performance', '5.1.1 Technology to Enhance Performance', 'tf', 'tf', 1, '{"question": "Streamlined swimwear is designed to reduce drag so a swimmer can hold a faster pace."}'::jsonb, '{"answer": true, "explain": "Low-drag, close-fitting racing suits reduce resistance moving through water, letting a swimmer hold a faster pace for longer."}'::jsonb),
('sport-studies:5-1-1-technology-to-enhance-performance:tf:92f8e76e', 'sport-studies', 'sport-studies:5-1-1-technology-to-enhance-performance', '5.1.1 Technology to Enhance Performance', 'tf', 'tf', 1, '{"question": "A carbon-fibre racket is heavier than an old wooden racket, which is why it improves performance."}'::jsonb, '{"answer": false, "explain": "It is the opposite — carbon fibre is lighter and stiffer than wood, giving more power and control with less arm fatigue."}'::jsonb),
('sport-studies:5-1-1-technology-to-enhance-performance:tf:c59a211a', 'sport-studies', 'sport-studies:5-1-1-technology-to-enhance-performance', '5.1.1 Technology to Enhance Performance', 'tf', 'tf', 1, '{"question": "GPS trackers mainly measure a player''s distance covered and effort during a session."}'::jsonb, '{"answer": true, "explain": "GPS vests record distance, speed and effort so a coach can plan training load — that is their main use."}'::jsonb),
('sport-studies:5-1-1-technology-to-enhance-performance:tf:094d4030', 'sport-studies', 'sport-studies:5-1-1-technology-to-enhance-performance', '5.1.1 Technology to Enhance Performance', 'tf', 'tf', 1, '{"question": "Video analysis is used to spot technical faults a performer cannot feel themselves."}'::jsonb, '{"answer": true, "explain": "Slowing footage down lets a coach see a specific fault, such as a start position or swing plane, that the performer cannot feel while doing it."}'::jsonb),
('sport-studies:5-1-1-technology-to-enhance-performance:tf:cb3110a1', 'sport-studies', 'sport-studies:5-1-1-technology-to-enhance-performance', '5.1.1 Technology to Enhance Performance', 'tf', 'tf', 1, '{"question": "Any equipment worn during a match, including a padded headguard, counts as technology that enhances performance."}'::jsonb, '{"answer": false, "explain": "A headguard''s main job is protecting the performer, not improving their performance — that makes it safety technology, not performance technology."}'::jsonb),
('sport-studies:5-1-1-technology-to-enhance-performance:tf:f84b84db', 'sport-studies', 'sport-studies:5-1-1-technology-to-enhance-performance', '5.1.1 Technology to Enhance Performance', 'tf', 'tf', 1, '{"question": "Naming a piece of technology without linking it to an effect on performance is usually enough to earn full marks."}'::jsonb, '{"answer": false, "explain": "Naming alone earns little. Marks come from linking the named technology to its specific effect on performance (lighter, stiffer, more aerodynamic, or better data)."}'::jsonb),
('sport-studies:5-1-1-technology-to-enhance-performance:learn:e1e0b717', 'sport-studies', 'sport-studies:5-1-1-technology-to-enhance-performance', '5.1.1 Technology to Enhance Performance', 'learn', 'mcq', 1, '{"readingTitle": "Streamlined clothing and aerodynamic materials", "reading": "<h4>Why ''aerodynamic'' and ''streamlined'' matter</h4>\n<ul>\n<li><strong>Aerodynamic</strong> equipment or clothing is shaped and made from materials that let air or water flow around the body with less resistance (\"drag\"). Less drag means a performer can move faster for the same amount of effort.</li>\n<li><strong>Streamlined</strong> clothing is cut close to the body, often from smooth, tight-fitting fabric, so it does not \"catch\" the air or water as the performer moves.</li>\n</ul>\n<h4>Named examples</h4>\n<ul>\n<li><strong>Swimming</strong> — competitive swimmers wear low-drag racing suits made from smooth, compressive fabric that reduces resistance moving through water, letting them hold a faster pace for longer.</li>\n<li><strong>Track cycling</strong> — sprint and time-trial cyclists wear one-piece aerodynamic skinsuits and aero helmets shaped to cut through the air, which matters hugely at high speed.</li>\n<li><strong>Alpine skiing</strong> — skiers wear tight, smooth racing suits so wind resistance does not slow their descent.</li>\n<li><strong>Athletics</strong> — sprinters often wear fitted, lightweight suits rather than loose kit, again to reduce air resistance over a short, explosive race.</li>\n</ul>\n<h4>The exam point</h4>\n<ul>\n<li>Always link the material/design feature to the actual effect: <em>close-fitting, smooth material → less drag → more speed for the same effort</em>. Naming \"swimsuits\" alone earns little; explaining the drag reduction is what earns marks.</li>\n</ul>", "question": "Why do elite cyclists and swimmers often wear tight-fitting, streamlined suits during competition?", "options": ["To reduce drag/resistance so they can move through air or water more efficiently", "To display sponsor logos more clearly to television audiences watching at home", "To meet a required uniform colour scheme set by the event''s organising committee", "To keep the performer warmer throughout a long, low-intensity training session"]}'::jsonb, '{"answer": 0, "explain": "Streamlined suits reduce drag through air or water, letting the performer move faster for the same effort — the other options describe branding, rules or warmth, not performance."}'::jsonb)
